+#[test]
+fn v2_sidecar_path_derives_from_jsonl_stem() {
+    let jsonl = Path::new("/tmp/sessions/my_session.jsonl");
+    let sidecar = pi::session_store_v2::v2_sidecar_path(jsonl);
+    assert_eq!(sidecar, Path::new("/tmp/sessions/my_session.v2"));
+}
