+#[test]
+fn has_v2_sidecar_returns_false_for_bare_jsonl() {
+    let dir = tempdir().unwrap();
+    let jsonl = dir.path().join("session.jsonl");
+    fs::write(&jsonl, "{}").unwrap();
+    assert!(!pi::session_store_v2::has_v2_sidecar(&jsonl));
+}
